        for (hr, min_in_conc, min_in_cmu, code) in [
            (1, 3.5, 4,  "IBC Table 722.5.2(1): 1-hr fire rating"),
            (2, 4.5, 6,  "IBC Table 722.5.2(1): 2-hr fire rating"),
            (3, 6.0, 8,  "IBC Table 722.5.2(1): 3-hr fire rating"),
