    // Rectangular profile in YZ plane, beam runs along X
    CurveArray loop = new CurveArray();
    loop.Append(Line.CreateBound(new XYZ(0, -b/2, -h),   new XYZ(0,  b/2, -h)));
    loop.Append(Line.CreateBound(new XYZ(0,  b/2, -h),   new XYZ(0,  b/2,  0)));
