        for b, d, bf, df, L, desc in l_cases:
            b_ft  = b  * MM_TO_FT
            d_ft  = d  * MM_TO_FT
            bf_ft = bf * MM_TO_FT
            df_ft = df * MM_TO_FT
            L_ft  = L  * MM_TO_FT
            samples.append(_s(
                f"Create a concrete L-beam (spandrel beam) family: {desc}, {L} mm span.",
                f"""\
