    CurveArrArray profile = new CurveArrArray();
    profile.Append(outerLoop);
    profile.Append(innerLoop);

    SketchPlane sp = SketchPlane.Create(familyDoc,
        Plane.CreateByNormalAndOrigin(XYZ.BasisX, XYZ.Zero));

