    int    segs   = 16;

    SketchPlane spZ = SketchPlane.Create(familyDoc,
        Plane.CreateByNormalAndOrigin(XYZ.BasisZ, XYZ.Zero));

    // Solid base panel
    CurveArrArray panProf = new CurveArrArray();
    CurveArray pl = new CurveArray();
    pl.Append(Line.CreateBound(new XYZ(-panW/2,-panD/2,0),new XYZ( panW/2,-panD/2,0)));
    pl.Append(Line.CreateBound(new XYZ( panW/2,-panD/2,0),new XYZ( panW/2, panD/2,0)));
    pl.Append(Line.CreateBound(new XYZ( panW/2, panD/2,0),new XYZ(-panW/2, panD/2,0)));
    pl.Append(Line.CreateBound(new XYZ(-panW/2, panD/2,0),new XYZ(-panW/2,-panD/2,0)));
    panProf.Append(pl);
    familyDoc.FamilyCreate.NewExtrusion(true, panProf, spZ, panThk);

    // Void holes
    double startX = -(nHoles - 1) * pitch / 2;
    double startY = -(nHoles - 1) * pitch / 2;

    for (int r = 0; r < nHoles; r++)
    {{
        for (int c = 0; c < nHoles; c++)
        {{
            double cx = startX + c * pitch;
            double cy = startY + r * pitch;

            CurveArray holeLoop = new CurveArray();
            for (int s = 0; s < segs; s++)
            {{
                double a0 = 2 * Math.PI * s / segs;
                double a1 = 2 * Math.PI * (s + 1) / segs;
                holeLoop.Append(Line.CreateBound(
                    new XYZ(cx + holeR*Math.Cos(a0), cy + holeR*Math.Sin(a0), 0),
                    new XYZ(cx + holeR*Math.Cos(a1), cy + holeR*Math.Sin(a1), 0)));
            }}
            CurveArrArray holeProf = new CurveArrArray();
            holeProf.Append(holeLoop);
            // isSolid=false creates void
            familyDoc.FamilyCreate.NewExtrusion(false, holeProf, spZ, panThk);
        }}
    }}

    tx.Commit();
}}""",
        ))

        # Slot cuts in a structural member
        samples.append(_s(
            "Create a structural beam family with horizontal rectangular slot cuts for web openings",
            f"""\
using Autodesk.Revit.DB;

// Beam with web slots: 200x400mm profile 3000mm long; 3 rectangular slot voids 100x200mm
using (Transaction tx = new Transaction(familyDoc, "Create Beam With Slots"))
{{
    tx.Start();

    double bW  = {_ft(200)};   // 200 mm flange width
    double bH  = {_ft(400)};   // 400 mm section height
    double bL  = {_ft(3000)};  // 3000 mm beam length
    double sW  = {_ft(100)};   // slot width
    double sH  = {_ft(200)};   // slot height
    int    nSlots = 3;

    SketchPlane spY = SketchPlane.Create(familyDoc,
        Plane.CreateByNormalAndOrigin(XYZ.BasisY, XYZ.Zero));

    // Solid beam extrusion along Y axis
    CurveArrArray beamProf = new CurveArrArray();
    CurveArray bl = new CurveArray();
    bl.Append(Line.CreateBound(new XYZ(-bW/2,0,0),    new XYZ( bW/2,0,0)));
    bl.Append(Line.CreateBound(new XYZ( bW/2,0,0),    new XYZ( bW/2,0,bH)));
    bl.Append(Line.CreateBound(new XYZ( bW/2,0,bH),   new XYZ(-bW/2,0,bH)));
    bl.Append(Line.CreateBound(new XYZ(-bW/2,0,bH),   new XYZ(-bW/2,0,0)));
    beamProf.Append(bl);
    familyDoc.FamilyCreate.NewExtrusion(true, beamProf, spY, bL);

    // Void slots at evenly spaced Y positions
    double slotCenterZ = bH / 2;
    double yStep = bL / (nSlots + 1);

    for (int i = 1; i <= nSlots; i++)
    {{
        double yCtr = -bL/2 + i * yStep;

        // Void profile in XZ plane at Y = yCtr
        SketchPlane spSlot = SketchPlane.Create(familyDoc,
            Plane.CreateByNormalAndOrigin(XYZ.BasisY, new XYZ(0, yCtr, 0)));

        CurveArrArray slotProf = new CurveArrArray();
        CurveArray sl = new CurveArray();
        sl.Append(Line.CreateBound(new XYZ(-sW/2, yCtr, slotCenterZ-sH/2),
                                   new XYZ( sW/2, yCtr, slotCenterZ-sH/2)));
        sl.Append(Line.CreateBound(new XYZ( sW/2, yCtr, slotCenterZ-sH/2),
                                   new XYZ( sW/2, yCtr, slotCenterZ+sH/2)));
        sl.Append(Line.CreateBound(new XYZ( sW/2, yCtr, slotCenterZ+sH/2),
                                   new XYZ(-sW/2, yCtr, slotCenterZ+sH/2)));
        sl.Append(Line.CreateBound(new XYZ(-sW/2, yCtr, slotCenterZ+sH/2),
                                   new XYZ(-sW/2, yCtr, slotCenterZ-sH/2)));
        slotProf.Append(sl);
        familyDoc.FamilyCreate.NewExtrusion(false, slotProf, spSlot, bW);
    }}

    tx.Commit();
}}""",
        ))

        # Hollow cylindrical void in a solid block
        samples.append(_s(
            "Create a void cylinder cut through the center of a solid rectangular block to form a tube shape",
            f"""\
using Autodesk.Revit.DB;
using System;

// Hollow tube: solid 300x300mm square block 500mm tall with 200mm diameter void bore
using (Transaction tx = new Transaction(familyDoc, "Create Hollow Tube"))
{{
    tx.Start();

    double blockSz = {_ft(300)};  // 300 mm
    double blockH  = {_ft(500)};  // 500 mm
    double voidR   = {_ft(100)};  // 100 mm (200mm dia bore)
    int    segs    = 24;

    SketchPlane spZ = SketchPlane.Create(familyDoc,
        Plane.CreateByNormalAndOrigin(XYZ.BasisZ, XYZ.Zero));

    // Outer solid block
    CurveArrArray blockProf = new CurveArrArray();
    CurveArray bl = new CurveArray();
    bl.Append(Line.CreateBound(new XYZ(-blockSz/2,-blockSz/2,0),new XYZ( blockSz/2,-blockSz/2,0)));
    bl.Append(Line.CreateBound(new XYZ( blockSz/2,-blockSz/2,0),new XYZ( blockSz/2, blockSz/2,0)));
    bl.Append(Line.CreateBound(new XYZ( blockSz/2, blockSz/2,0),new XYZ(-blockSz/2, blockSz/2,0)));
    bl.Append(Line.CreateBound(new XYZ(-blockSz/2, blockSz/2,0),new XYZ(-blockSz/2,-blockSz/2,0)));
    blockProf.Append(bl);
    familyDoc.FamilyCreate.NewExtrusion(true, blockProf, spZ, blockH);

    // Void cylinder along Z axis
    CurveArray voidLoop = new CurveArray();
    for (int s = 0; s < segs; s++)
    {{
        double a0 = 2 * Math.PI * s / segs;
        double a1 = 2 * Math.PI * (s + 1) / segs;
        voidLoop.Append(Line.CreateBound(
            new XYZ(voidR * Math.Cos(a0), voidR * Math.Sin(a0), 0),
            new XYZ(voidR * Math.Cos(a1), voidR * Math.Sin(a1), 0)));
    }}
    CurveArrArray voidProf = new CurveArrArray();
    voidProf.Append(voidLoop);
    familyDoc.FamilyCreate.NewExtrusion(false, voidProf, spZ, blockH);

    tx.Commit();
}}""",
        ))

        # Keyway slot
        samples.append(_s(
            "Create a shaft family with a rectangular keyway slot void cut along its length",
            f"""\
using Autodesk.Revit.DB;
using System;

// Shaft with keyway: 50mm radius cylinder 300mm long, 10x6mm keyway void
using (Transaction tx = new Transaction(familyDoc, "Create Keyed Shaft"))
{{
    tx.Start();

    double shaftR  = {_ft(50)};   // 50 mm shaft radius
    double shaftL  = {_ft(300)};  // 300 mm length
    double keyW    = {_ft(10)};   // 10 mm keyway width
    double keyH    = {_ft(6)};    // 6 mm keyway depth
    int    segs    = 24;

    SketchPlane spZ = SketchPlane.Create(familyDoc,
        Plane.CreateByNormalAndOrigin(XYZ.BasisZ, XYZ.Zero));

    // Shaft body (cylinder)
    CurveArray shaftLoop = new CurveArray();
    for (int s = 0; s < segs; s++)
    {{
        double a0 = 2 * Math.PI * s / segs;
        double a1 = 2 * Math.PI * (s + 1) / segs;
        shaftLoop.Append(Line.CreateBound(
            new XYZ(shaftR*Math.Cos(a0), shaftR*Math.Sin(a0), 0),
            new XYZ(shaftR*Math.Cos(a1), shaftR*Math.Sin(a1), 0)));
    }}
    CurveArrArray shaftProf = new CurveArrArray();
    shaftProf.Append(shaftLoop);
    familyDoc.FamilyCreate.NewExtrusion(true, shaftProf, spZ, shaftL);

    // Keyway void: rectangular slot at top of shaft (Y = shaftR upward)
    // Void profile in XY plane; extruded along Z (shaft axis)
    double keyStartY = shaftR - keyH;
    CurveArray keyLoop = new CurveArray();
    keyLoop.Append(Line.CreateBound(new XYZ(-keyW/2, keyStartY,     0),
                                    new XYZ( keyW/2, keyStartY,     0)));
    keyLoop.Append(Line.CreateBound(new XYZ( keyW/2, keyStartY,     0),
                                    new XYZ( keyW/2, shaftR + keyH, 0)));
    keyLoop.Append(Line.CreateBound(new XYZ( keyW/2, shaftR + keyH, 0),
                                    new XYZ(-keyW/2, shaftR + keyH, 0)));
    keyLoop.Append(Line.CreateBound(new XYZ(-keyW/2, shaftR + keyH, 0),
                                    new XYZ(-keyW/2, keyStartY,     0)));
    CurveArrArray keyProf = new CurveArrArray();
    keyProf.Append(keyLoop);
    familyDoc.FamilyCreate.NewExtrusion(false, keyProf, spZ, shaftL);

    tx.Commit();
}}""",
        ))

        # Angled chamfer void
        samples.append(_s(
            "Cut a 45-degree chamfer void on all four top edges of a rectangular block",
            f"""\
using Autodesk.Revit.DB;

// 45-degree edge chamfer on a 300x300x200mm block using four triangular void extrusions
using (Transaction tx = new Transaction(familyDoc, "Create Chamfered Block"))
{{
    tx.Start();

    double W = {_ft(300)};  // 300 mm
    double D = {_ft(300)};  // 300 mm
    double H = {_ft(200)};  // 200 mm
    double C = {_ft(20)};   // 20 mm chamfer

    SketchPlane spZ = SketchPlane.Create(familyDoc,
        Plane.CreateByNormalAndOrigin(XYZ.BasisZ, XYZ.Zero));

    // Main solid block
    CurveArrArray blockProf = new CurveArrArray();
    CurveArray bl = new CurveArray();
    bl.Append(Line.CreateBound(new XYZ(-W/2,-D/2,0),new XYZ( W/2,-D/2,0)));
    bl.Append(Line.CreateBound(new XYZ( W/2,-D/2,0),new XYZ( W/2, D/2,0)));
    bl.Append(Line.CreateBound(new XYZ( W/2, D/2,0),new XYZ(-W/2, D/2,0)));
    bl.Append(Line.CreateBound(new XYZ(-W/2, D/2,0),new XYZ(-W/2,-D/2,0)));
    blockProf.Append(bl);
    familyDoc.FamilyCreate.NewExtrusion(true, blockProf, spZ, H);

    // Front edge chamfer void (Y = -D/2): triangular profile in XZ plane
    SketchPlane spFront = SketchPlane.Create(familyDoc,
        Plane.CreateByNormalAndOrigin(XYZ.BasisY, new XYZ(0, -D/2 - C/2, 0)));

    // Triangle: at top of block, height C, width C (45deg)
    CurveArrArray chamProf = new CurveArrArray();
    CurveArray chamL = new CurveArray();
    double topZ = H;
    double yEdge = -D/2;
    chamL.Append(Line.CreateBound(new XYZ(-W/2,     yEdge, topZ),     new XYZ(W/2,      yEdge, topZ)));
    chamL.Append(Line.CreateBound(new XYZ( W/2,     yEdge, topZ),     new XYZ(W/2,      yEdge - C, topZ)));
    chamL.Append(Line.CreateBound(new XYZ( W/2,     yEdge - C, topZ), new XYZ(-W/2,     yEdge - C, topZ)));
    chamL.Append(Line.CreateBound(new XYZ(-W/2,     yEdge - C, topZ), new XYZ(-W/2,     yEdge, topZ)));
    chamProf.Append(chamL);

    // Extrude void in Z direction (downward -C)
    SketchPlane spTopCham = SketchPlane.Create(familyDoc,
        Plane.CreateByNormalAndOrigin(XYZ.BasisZ, new XYZ(0, 0, H)));
    CurveArrArray topChamProf = new CurveArrArray();
    CurveArray tcl = new CurveArray();
    tcl.Append(Line.CreateBound(new XYZ(-W/2,   -D/2,    H), new XYZ( W/2,   -D/2,    H)));
    tcl.Append(Line.CreateBound(new XYZ( W/2,   -D/2,    H), new XYZ( W/2,   -D/2+C,  H)));
    tcl.Append(Line.CreateBound(new XYZ( W/2,   -D/2+C,  H), new XYZ(-W/2,   -D/2+C,  H)));
    tcl.Append(Line.CreateBound(new XYZ(-W/2,   -D/2+C,  H), new XYZ(-W/2,   -D/2,    H)));
    topChamProf.Append(tcl);
    Extrusion chamVoid = familyDoc.FamilyCreate.NewExtrusion(false, topChamProf, spTopCham, C);
    chamVoid.StartOffset = -C;

    tx.Commit();
}}""",
        ))

        return samples

tool_input.content:
"""Training data generator: MEP Revit family connectors and equipment.

Produces ~250 Alpaca-format training pairs covering pipe connectors, duct
connectors, conduit connectors, pipe/duct fittings, equipment families,
electrical fixtures, sprinkler heads, plumbing fixtures, and connector
parameter patterns.
"""

from __future__ import annotations

from typing import Any, Dict, List

SAMPLE = Dict[str, Any]
MM_TO_FT = 1.0 / 304.8


def _s(instruction: str, output: str) -> SAMPLE:
    return {"instruction": instruction, "input": "", "output": output}


def _ft(mm: float) -> str:
    return f"{mm * MM_TO_FT:.6f}"


class MEPFamilyGenerator:
    """Generates training samples for Revit MEP family connector creation."""

    def generate(self) -> List[SAMPLE]:
        samples: List[SAMPLE] = []
        samples += self._pipe_connectors()
        samples += self._duct_connectors()
        samples += self._conduit_connectors()
        samples += self._pipe_fittings()
        samples += self._duct_fittings()
        samples += self._equipment_families()
        samples += self._electrical_fixtures()
        samples += self._sprinkler_heads()
        samples += self._plumbing_fixtures()
        samples += self._connector_parameters()
        return samples

    # ------------------------------------------------------------------
    # Pipe connectors
    # ------------------------------------------------------------------

    def _pipe_connectors(self) -> List[SAMPLE]:
        samples = []

        # Basic single pipe connector cases
        cases = [
            (50,  "supply", "SupplyHydronic", "Add a 50mm supply pipe connector to a Revit family"),
            (100, "return", "ReturnHydronic",  "Add a 100mm return hydronic pipe connector"),
            (25,  "supply", "SupplyHydronic",  "Add a 25mm domestic cold water pipe connector"),
            (75,  "supply", "OtherPipe",        "Add a 75mm generic pipe connector with supply direction"),
            (150, "bidirectional", "SupplyHydronic", "Add a 150mm bidirectional pipe connector"),
        ]
        for dia_mm, flow_label, sys_type, instruction in cases:
            dia_ft = dia_mm * MM_TO_FT
            flow_enum = {
                "supply": "FlowDirectionType.In",
                "return": "FlowDirectionType.Out",
                "bidirectional": "FlowDirectionType.Bidirectional",
            }[flow_label]
            samples.append(_s(instruction, f"""\
using Autodesk.Revit.DB;
using Autodesk.Revit.DB.Plumbing;

// Add pipe connector: diameter {dia_mm} mm, flow {flow_label}, system {sys_type}
// ConnectorManager is obtained from the family's MEP model -- no Transaction needed for connector setup
using (Transaction tx = new Transaction(familyDoc, "Add Pipe Connector"))
{{
    tx.Start();

    double diameter = {dia_ft:.6f}; // {dia_mm} mm

    // Place connector origin at family origin (adjust XYZ for actual port location)
    ConnectorElement pipeConn = ConnectorElement.CreatePipeConnector(
        familyDoc,
        PipeSystemType.{sys_type},
        diameter,
        XYZ.Zero);

    pipeConn.FlowDirection = {flow_enum};

    tx.Commit();
}}"""))

        # Connector with explicit origin positions
        port_cases = [
            (50,  "XYZ.Zero",                             "inlet at origin"),
            (50,  f"new XYZ(0, 0, {_ft(500)})",          "outlet 500mm above origin"),
            (80,  f"new XYZ({_ft(200)}, 0, 0)",          "side connector 200mm offset"),
            (100, f"new XYZ(0, {_ft(-150)}, 0)",         "connector offset -150mm in Y"),
        ]
        for dia_mm, origin_expr, desc in port_cases:
            dia_ft = dia_mm * MM_TO_FT
            samples.append(_s(
                f"Add a {dia_mm}mm pipe connector at {desc}",
                f"""\
using Autodesk.Revit.DB;
using Autodesk.Revit.DB.Plumbing;

// Pipe connector at {desc}
using (Transaction tx = new Transaction(familyDoc, "Add Pipe Connector"))
{{
    tx.Start();

    double diameter = {dia_ft:.6f}; // {dia_mm} mm

    ConnectorElement pipeConn = ConnectorElement.CreatePipeConnector(
        familyDoc,
        PipeSystemType.SupplyHydronic,
        diameter,
        {origin_expr});

    pipeConn.FlowDirection = FlowDirectionType.In;

    tx.Commit();
}}"""))

        # Pair of inlet + outlet connectors
        samples.append(_s(
            "Add a pair of 65mm pipe connectors (inlet and outlet) to a pipe fitting family",
            f"""\
using Autodesk.Revit.DB;
using Autodesk.Revit.DB.Plumbing;

// Inlet connector at bottom, outlet connector at top
using (Transaction tx = new Transaction(familyDoc, "Add Pipe Connector Pair"))
{{
    tx.Start();

    double diameter = {65 * MM_TO_FT:.6f}; // 65 mm

    // Inlet -- fluid enters the fitting
    ConnectorElement inlet = ConnectorElement.CreatePipeConnector(
        familyDoc,
        PipeSystemType.SupplyHydronic,
        diameter,
        new XYZ(0, 0, {-300 * MM_TO_FT:.6f})); // -300 mm
    inlet.FlowDirection = FlowDirectionType.In;

    // Outlet -- fluid exits the fitting
    ConnectorElement outlet = ConnectorElement.CreatePipeConnector(
        familyDoc,
        PipeSystemType.SupplyHydronic,
        diameter,
        new XYZ(0, 0, {300 * MM_TO_FT:.6f})); // +300 mm
    outlet.FlowDirection = FlowDirectionType.Out;

    tx.Commit();
}}"""))

        # Connector with angle (not aligned to Z)
        samples.append(_s(
            "Add a 50mm pipe connector pointing in the +X direction (horizontal branch)",
            f"""\
using Autodesk.Revit.DB;
using Autodesk.Revit.DB.Plumbing;

// Horizontal pipe connector -- connector direction set via transform
using (Transaction tx = new Transaction(familyDoc, "Add Horizontal Pipe Connector"))
{{
    tx.Start();

    double diameter = {50 * MM_TO_FT:.6f}; // 50 mm

    ConnectorElement conn = ConnectorElement.CreatePipeConnector(
        familyDoc,
        PipeSystemType.SupplyHydronic,
        diameter,
        new XYZ({200 * MM_TO_FT:.6f}, 0, 0)); // 200 mm along X

    // Rotate connector to point in +X direction
    conn.SetCoordinateSystem(new Transform(Transform.Identity)
    {{
        Origin = new XYZ({200 * MM_TO_FT:.6f}, 0, 0),
        BasisX = XYZ.BasisY,
        BasisY = XYZ.BasisZ,
        BasisZ = XYZ.BasisX  // connector faces +X
    }});

    conn.FlowDirection = FlowDirectionType.Out;

    tx.Commit();
}}"""))

        # Pressure/flow parameter on connector
        samples.append(_s(
            "Create a pipe connector with flow rate and pressure drop parameters",
            f"""\
using Autodesk.Revit.DB;
using Autodesk.Revit.DB.Plumbing;

// FamilyManager parameter setup (OUTSIDE Transaction)
FamilyManager famMgr = familyDoc.FamilyManager;
FamilyParameter pFlow = famMgr.AddParameter(
    "Connector Flow",
    BuiltInParameterGroup.PG_MECHANICAL_FLOW,
    ParameterType.PipeFlow,
    false); // type parameter
famMgr.Set(pFlow, 0.0); // default 0 L/s

using (Transaction tx = new Transaction(familyDoc, "Add Pipe Connector"))
{{
    tx.Start();

    double diameter = {50 * MM_TO_FT:.6f}; // 50 mm

    ConnectorElement conn = ConnectorElement.CreatePipeConnector(
        familyDoc,
        PipeSystemType.SupplyHydronic,
        diameter,
        XYZ.Zero);

    conn.FlowDirection = FlowDirectionType.In;

    // Assign flow parameter to connector
    Parameter flowParam = conn.get_Parameter(BuiltInParameter.RBS_PIPE_FLOW_PARAM);
    if (flowParam != null && !flowParam.IsReadOnly)
        flowParam.Set(0.001); // 0.001 m3/s = 1 L/s

    tx.Commit();
}}"""))

        # Multiple system types
        sys_cases = [
            ("DomesticHotWater",  "hot water",   60),
            ("DomesticColdWater", "cold water",  20),
            ("FireProtectWet",    "fire sprinkler wet",  25),
            ("FireProtectDry",    "fire sprinkler dry",  25),
            ("OtherPipe",         "process pipe", 100),
            ("Vent",              "plumbing vent", 50),
            ("Sanitary",          "sanitary drain", 100),
        ]
        for sys_type, label, dia_mm in sys_cases:
            dia_ft = dia_mm * MM_TO_FT
            samples.append(_s(
                f"Add a {dia_mm}mm {label} pipe connector (PipeSystemType.{sys_type})",
                f"""\
using Autodesk.Revit.DB;
using Autodesk.Revit.DB.Plumbing;

// {label} pipe connector
using (Transaction tx = new Transaction(familyDoc, "Add {label.title()} Connector"))
{{
    tx.Start();

    double diameter = {dia_ft:.6f}; // {dia_mm} mm

    ConnectorElement conn = ConnectorElement.CreatePipeConnector(
        familyDoc,
        PipeSystemType.{sys_type},
        diameter,
        XYZ.Zero);

    conn.FlowDirection = FlowDirectionType.In;

    tx.Commit();
}}"""))

        # Diameter-driven by family parameter
        samples.append(_s(
            "Create a pipe connector whose diameter is driven by a family parameter",
            f"""\
using Autodesk.Revit.DB;
using Autodesk.Revit.DB.Plumbing;

// Step 1: Define diameter parameter (OUTSIDE Transaction)
FamilyManager famMgr = familyDoc.FamilyManager;
FamilyParameter pDiam = famMgr.AddParameter(
    "Connector Diameter",
    BuiltInParameterGroup.PG_GEOMETRY,
    ParameterType.Length,
    false);
famMgr.Set(pDiam, {50 * MM_TO_FT:.6f}); // default 50 mm

// Step 2: Create connector using current default value
using (Transaction tx = new Transaction(familyDoc, "Add Parametric Pipe Connector"))
{{
    tx.Start();

    double diameter = {50 * MM_TO_FT:.6f}; // 50 mm default

    ConnectorElement conn = ConnectorElement.CreatePipeConnector(
        familyDoc,
        PipeSystemType.SupplyHydronic,
        diameter,
        XYZ.Zero);

    conn.FlowDirection = FlowDirectionType.In;

    // Link connector radius parameter to family parameter
    Parameter connDiamParam = conn.get_Parameter(BuiltInParameter.CONNECTOR_RADIUS);
    if (connDiamParam != null)
        famMgr.AssociateElementParameterToFamilyParameter(connDiamParam, pDiam);

    tx.Commit();
}}"""))

        return samples

    # ------------------------------------------------------------------
    # Duct connectors
    # ------------------------------------------------------------------

    def _duct_connectors(self) -> List[SAMPLE]:
        samples = []

        # Rectangular duct connectors
        rect_cases = [
            (400, 200, "supply", "SupplyAir",  "Add a 400x200mm rectangular supply air duct connector"),
            (600, 300, "return", "ReturnAir",  "Add a 600x300mm rectangular return air duct connector"),
            (300, 300, "supply", "SupplyAir",  "Add a 300x300mm square supply duct connector"),
            (800, 400, "exhaust","ExhaustAir", "Add a 800x400mm exhaust duct connector"),
            (250, 150, "supply", "SupplyAir",  "Add a 250x150mm small supply duct connector"),
        ]
        for w_mm, h_mm, flow_label, sys_type, instruction in rect_cases:
            w_ft = w_mm * MM_TO_FT
            h_ft = h_mm * MM_TO_FT
            flow_enum = {
                "supply": "FlowDirectionType.In",
                "return": "FlowDirectionType.Out",
                "exhaust": "FlowDirectionType.Out",
            }[flow_label]
            samples.append(_s(instruction, f"""\
using Autodesk.Revit.DB;
using Autodesk.Revit.DB.Mechanical;

// Rectangular duct connector: {w_mm} x {h_mm} mm, {flow_label} air
using (Transaction tx = new Transaction(familyDoc, "Add Duct Connector"))
{{
    tx.Start();

    double width  = {w_ft:.6f}; // {w_mm} mm
    double height = {h_ft:.6f}; // {h_mm} mm

    ConnectorElement ductConn = ConnectorElement.CreateDuctConnector(
        familyDoc,
        DuctSystemType.{sys_type},
        ConnectorProfileType.Rectangular,
        XYZ.Zero);

    ductConn.Width  = width;
    ductConn.Height = height;
    ductConn.FlowDirection = {flow_enum};

    tx.Commit();
}}"""))

        # Round duct connectors
        round_cases = [
            (200, "supply", "SupplyAir",  "Add a 200mm round supply duct connector"),
