// Curtain wall panel: template is 'Curtain Wall Panel' or 'Metric Curtain Wall Panel'.
// The panel fills a grid cell; Width/Height flex with the grid.
// Origin at bottom-left corner of the cell.
FamilyManager famMgr = familyDoc.FamilyManager;

// Thickness parameter
FamilyParameter pThk = famMgr.AddParameter(
    "Panel Thickness", BuiltInParameterGroup.PG_GEOMETRY, ParameterType.Length, false);
famMgr.Set(pThk, 0.039370); // 12 mm glass

using (Transaction tx = new Transaction(familyDoc, "Create Curtain Panel"))
{
    tx.Start();

    // Panel dimensions driven by grid: use built-in 'Width' and 'Height'
    // which are automatically set by the curtain wall system.
    // Here we use nominal 1000x2400mm for standalone authoring.
    double pw = 3.280840; // 1000 mm
    double ph = 7.874016; // 2400 mm
    double pt = 0.039370; // 12 mm thickness

    // Frame border
    double border = 0.164042; // 50 mm frame width

    SketchPlane spFace = SketchPlane.Create(familyDoc,
        Plane.CreateByNormalAndOrigin(XYZ.BasisY, XYZ.Zero));

    // Glass infill (inner area, thin)
    double iw = pw - 2 * border;
    double ih = ph - 2 * border;
    CurveArray glassLoop = new CurveArray();
    glassLoop.Append(Line.CreateBound(new XYZ(border,    0, border),    new XYZ(border+iw, 0, border)));
    glassLoop.Append(Line.CreateBound(new XYZ(border+iw, 0, border),    new XYZ(border+iw, 0, border+ih)));
