    def _wall_reveal_profiles(self) -> List[SAMPLE]:
        samples: List[SAMPLE] = []

        reveal_cases = [
            (25, 15, "narrow reveal channel 25mm wide, 15mm deep"),
            (50, 25, "standard reveal 50mm wide, 25mm deep"),
            (75, 40, "deep reveal channel 75mm wide, 40mm deep"),
        ]
        for w, d, desc in reveal_cases:
            w_ft = f"{w * MM_TO_FT:.6f}"
            d_ft = f"{d * MM_TO_FT:.6f}"
            samples.append(_s(
                f"Create a wall reveal profile family: {desc}",
                f"""\
using Autodesk.Revit.DB;

// Wall reveal profiles are 2D profile families (Profile-Reveal template).
// The profile is the cross-section of the reveal channel cut into the wall.
// Origin at the centre of the reveal mouth on the wall face.
using (Transaction tx = new Transaction(familyDoc, "Create Reveal Profile"))
{{
    tx.Start();

    double rw = {w_ft};  // {w} mm reveal width
    double rd = {d_ft};  // {d} mm reveal depth

    // Profile: rectangular channel (open at wall face, closed inside)
    // The reveal profile is drawn as a closed loop representing the
    // cross-section shape that will be swept along the wall.
    // Positive Y = into the wall; X = width direction.
    CurveArray loop = new CurveArray();
    loop.Append(Line.CreateBound(new XYZ(-rw/2, 0, 0),  new XYZ( rw/2, 0, 0)));   // face opening
    loop.Append(Line.CreateBound(new XYZ( rw/2, 0, 0),  new XYZ( rw/2, rd, 0)));  // right side
    loop.Append(Line.CreateBound(new XYZ( rw/2, rd, 0), new XYZ(-rw/2, rd, 0)));  // back
    loop.Append(Line.CreateBound(new XYZ(-rw/2, rd, 0), new XYZ(-rw/2, 0, 0)));   // left side

    CurveArrArray profile = new CurveArrArray();
    profile.Append(loop);

    // In a Profile family, geometry is drawn directly as 2D curves
    // (no extrusion); this represents the sweep cross-section.
    SketchPlane sp = SketchPlane.Create(familyDoc,
        Plane.CreateByNormalAndOrigin(XYZ.BasisZ, XYZ.Zero));

    // Store profile curves as model lines for reference
    familyDoc.FamilyCreate.NewModelCurveArray(profile, sp);

    tx.Commit();
}}""",
