            """\
using Autodesk.Revit.DB;
using System;

// Ogee moulding: S-curve profile for wall sweep / cornice
// Approximated with straight line segments for Revit compatibility
using (Transaction tx = new Transaction(familyDoc, "Create Ogee Profile"))
{
    tx.Start();

    double height = 0.246063; // 75 mm total height
    double width  = 0.196850; // 60 mm projection
    int n = 8; // segments per arc

    CurveArray loop = new CurveArray();

    // Bottom flat (base)
    loop.Append(Line.CreateBound(new XYZ(0, 0, 0), new XYZ(width * 0.2, 0, 0)));

    // Lower convex arc (quarter circle, curves outward)
    double r1 = height * 0.4;
    XYZ c1 = new XYZ(width * 0.2 + r1, 0, r1);
    for (int i = 0; i < n; i++)
    {
        double a0 = Math.PI + Math.PI * 0.5 * i / n;
        double a1 = Math.PI + Math.PI * 0.5 * (i + 1) / n;
        XYZ p0 = new XYZ(c1.X + r1 * Math.Cos(a0), 0, c1.Z + r1 * Math.Sin(a0));
        XYZ p1 = new XYZ(c1.X + r1 * Math.Cos(a1), 0, c1.Z + r1 * Math.Sin(a1));
        loop.Append(Line.CreateBound(p0, p1));
    }

    // Upper concave arc (quarter circle, curves inward)
    double r2 = height * 0.4;
    XYZ c2 = new XYZ(width * 0.8 - r2, 0, height - r2);
    for (int i = 0; i < n; i++)
    {
        double a0 = 0 + Math.PI * 0.5 * i / n;
        double a1 = 0 + Math.PI * 0.5 * (i + 1) / n;
        XYZ p0 = new XYZ(c2.X + r2 * Math.Cos(a0), 0, c2.Z + r2 * Math.Sin(a0));
        XYZ p1 = new XYZ(c2.X + r2 * Math.Cos(a1), 0, c2.Z + r2 * Math.Sin(a1));
        loop.Append(Line.CreateBound(p0, p1));
    }

    // Top flat
    loop.Append(Line.CreateBound(new XYZ(width * 0.8, 0, height), new XYZ(0, 0, height)));
    // Back edge (wall face)
    loop.Append(Line.CreateBound(new XYZ(0, 0, height), new XYZ(0, 0, 0)));

    CurveArrArray profile = new CurveArrArray();
    profile.Append(loop);

    SketchPlane sp = SketchPlane.Create(familyDoc,
        Plane.CreateByNormalAndOrigin(XYZ.BasisZ, XYZ.Zero));
    familyDoc.FamilyCreate.NewModelCurveArray(profile, sp);

    tx.Commit();
}""",
